#!/bin/bash
set -e
cd ~/BrandexOsv2
mkdir -p components/modals components/layout lib app/\(dashboard\)
echo "Instalando archivos de Braindex OS..."

echo "" | base64 -d > components/modals/TaskModal.tsx
echo "  ✓ components/modals/TaskModal.tsx"

echo "" | base64 -d > components/modals/ProjectModal.tsx
echo "  ✓ components/modals/ProjectModal.tsx"

echo "" | base64 -d > components/modals/EntityModal.tsx
echo "  ✓ components/modals/EntityModal.tsx"

echo "" | base64 -d > components/modals/ClientDetail.tsx
echo "  ✓ components/modals/ClientDetail.tsx"

